      "Check understanding: 'Why do plant cells have a wall but animal cells don't?'"
    ],
    "conceptFlow": [
      {
        "conceptName": "Discovery of the Cell",
        "definition": "The observation of dead cork tissue by Robert Hooke in 1665 using a primitive microscope.",
        "coreExplanation": "Hooke observed empty compartments which he named 'cells' because they resembled monk's cells. He did not see living protoplasm, only cell walls.",
        "importance": "Marks the beginning of Cell Theory and modern biology.",
        "observedIn": [
          "Microscope slides of cork",
          "Historical illustrations"
        ],
        "whyStudyIt": "To understand the history of scientific discovery and the origin of biological terminology.",
