        "expectedResponse": "Presence of nucleus.",
        "answerPoints": [
          "Eukaryotes have true nucleus with membrane",
          "Prokaryotes lack nuclear membrane"
        ]
      },
      {
        "question": "Why do plant cells need a cell wall but animal cells don't?",
        "level": "Application",
        "expectedResponse": "Support and protection.",
        "answerPoints": [
          "Plants are stationary, need rigidity against gravity/wind",
          "Cellulose provides structural strength"
        ]
      }
    ],
